def get_min_coins_greedy(amount: int) -> int:
    denominations = [25, 10, 5, 1]  # Quarters, Dimes, Nickels, Pennies (common US denominations)
    total_coins = 0

    for coin in denominations:
        if amount == 0:
            break

        num_coins_of_this_type = amount // coin
        total_coins += num_coins_of_this_type
        amount %= coin

    return total_coins
